// Split the stories array into individual items
// and enrich each story with tenant-level metadata
const body = $input.first().json.body;
const stories = body.stories || [];

if (stories.length === 0) {
  throw new Error('No stories found in payload');
}

return stories.map(story => ({
  json: {
    ...story,
    tenant_id: body.tenant_id,
    tenant_name: body.tenant_name,
    last_synced_at: body.last_synced_at
  }
}));

// Structural validation — no AI, fast, deterministic, free
// Catches broken data before it hits the API
const items = $input.all();
const results = [];

for (const item of items) {
  const story = item.json;
  const issues = [];

  // Check story_title exists and is not empty
  if (!story.story_title || String(story.story_title).trim() === '') {
    issues.push({ type: 'missing_title', page: null, detail: 'Story title is missing or empty' });
  }

  // Check pages array has at least one item
  if (!story.pages || !Array.isArray(story.pages) || story.pages.length === 0) {
    issues.push({ type: 'no_pages', page: null, detail: 'Story has no pages' });
  } else {
    for (const page of story.pages) {
      // Each page must have an asset_url
      if (!page.asset_url || String(page.asset_url).trim() === '') {
        issues.push({ type: 'missing_asset', page: page.page_id, detail: 'Page ' + page.page_id + ' is missing asset_url' });
      }
      // Each action must have both cta and url
      if (page.action) {
        if (!page.action.cta || String(page.action.cta).trim() === '') {
          issues.push({ type: 'missing_cta', page: page.page_id, detail: 'Page ' + page.page_id + ' action is missing CTA text' });
        }
        if (!page.action.url || String(page.action.url).trim() === '') {
          issues.push({ type: 'missing_action_url', page: page.page_id, detail: 'Page ' + page.page_id + ' action is missing URL' });
        }
      }
    }
  }

  results.push({
    json: {
      ...story,
      structure_valid: issues.length === 0,
      structure_issues: issues
    }
  });
}

return results;

// Prepare prompt strings for the Basic LLM Chain + OpenRouter Chat Model
// No more raw HTTP request body — we use the native n8n OpenRouter node
const items = $input.all();
const results = [];

for (const item of items) {
  const story = item.json;
  const storyData = {
    story_id: story.story_id,
    story_title: story.story_title,
    pages: story.pages,
    context: story.context
  };

  results.push({
    json: {
      story_id: story.story_id,
      tenant_id: story.tenant_id,
      tenant_name: story.tenant_name,
      chatInput: 'Story data:\n' + JSON.stringify(storyData, null, 2)
    }
  });
}

return results;

// Parse AI response from the Basic LLM Chain output
// With json_object response format, the chain outputs parsed JSON directly into $json
const items = $input.all();
const origItems = $('Prepare AI Request').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const orig = origItems[i].json;

  try {
    let result;

    if (item.status && (item.status === 'ok' || item.status === 'review' || item.status === 'invalid')) {
      // Already parsed JSON from LLM Chain json_object mode
      result = item;
    } else if (item.text || item.output) {
      // Fallback: text output that needs parsing
      const aiContent = item.text || item.output || '';
      const jsonMatch = aiContent.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        result = JSON.parse(jsonMatch[0]);
      } else {
        throw new Error('No JSON found in AI response');
      }
    } else {
      throw new Error('Unexpected AI response format: ' + JSON.stringify(Object.keys(item)));
    }

    if (!result.status || !['ok', 'review', 'invalid'].includes(result.status)) {
      result.status = 'review';
    }

    results.push({
      json: {
        story_id: result.story_id || orig.story_id,
        tenant_id: orig.tenant_id,
        tenant_name: orig.tenant_name,
        status: result.status,
        confidence: result.confidence || 'low',
        issues: result.issues || [],
        summary: result.summary || 'AI evaluation completed',
        error_message: null
      }
    });
  } catch (error) {
    results.push({
      json: {
        story_id: orig.story_id,
        tenant_id: orig.tenant_id,
        tenant_name: orig.tenant_name,
        status: 'error',
        confidence: null,
        issues: [],
        summary: null,
        error_message: 'AI evaluation failed: ' + error.message
      }
    });
  }
}

return results;

// Format structurally invalid stories into the standard result shape
const items = $input.all();
const results = [];

for (const item of items) {
  const story = item.json;
  results.push({
    json: {
      story_id: story.story_id,
      tenant_id: story.tenant_id,
      tenant_name: story.tenant_name,
      status: 'invalid_structure',
      confidence: 'high',
      issues: story.structure_issues,
      summary: 'Structural validation failed: ' + story.structure_issues.length + ' issue(s) found',
      error_message: null
    }
  });
}

return results;

// Build parameterised INSERT query for Neon
// Both valid and invalid paths converge here with the same shape
// IMPORTANT: We keep all result fields on the output so downstream nodes
// can reference $json directly without paired-item issues
const items = $input.all();
const results = [];

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

for (const item of items) {
  const r = item.json;
  const issuesJson = r.issues && r.issues.length > 0
    ? esc(JSON.stringify(r.issues)) + '::jsonb'
    : 'NULL';

  const query = 'INSERT INTO story_qa_results (story_id, tenant_id, tenant_name, status, confidence, issues, summary, error_message) VALUES ('
    + esc(r.story_id) + ', '
    + esc(r.tenant_id) + ', '
    + esc(r.tenant_name) + ', '
    + esc(r.status) + ', '
    + esc(r.confidence) + ', '
    + issuesJson + ', '
    + esc(r.summary) + ', '
    + esc(r.error_message) + ')';

  results.push({
    json: { ...r, query }
  });
}

return results;

const origItems = $('Build DB Query').all();
return origItems.map(item => ({
  json: {
    story_id: item.json.story_id,
    tenant_id: item.json.tenant_id,
    tenant_name: item.json.tenant_name,
    status: item.json.status,
    confidence: item.json.confidence,
    issues: item.json.issues,
    summary: item.json.summary,
    error_message: item.json.error_message
  }
}));
